const isSameCell = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
  ax === bx && ay === by;

const areNeighbors = ([ax, ay]: Cell, [bx, by]: Cell): boolean =>
  Math.abs(ax - bx) <= 1 && Math.abs(ay - by) <= 1;

const countLiveNeighbors = (cell: Cell, liveCells: Cell[]): number =>
  liveCells.filter(
    (other) => !isSameCell(cell, other) && areNeighbors(cell, other),
  ).length;
